```typescript
import { Effect } from "effect"

interface Graph<T> {
  nodes: T[]
  edges: [from: T, to: T][]
}

export function toposort<T>(graph: Graph<T>): T[] {
  // Build adjacency list and in-degree map
  const adjList = new Map<T, T[]>()
  const inDegree = new Map<T, number>()

  // Initialize all nodes with zero in-degree and empty adjacency lists
  for (const node of graph.nodes) {
    adjList.set(node, [])
    inDegree.set(node, 0)
  }

  // Process edges to build the graph structure and track in-degrees
  for (const [from, to] of graph.edges) {
    adjList.get(from)!.push(to)
    inDegree.set(to, (inDegree.get(to) ?? 0) + 1)
  }

  // Kahn's algorithm: start with nodes that have no incoming edges
  const queue: T[] = []
  for (const [node, degree] of inDegree.entries()) {
    if (degree === 0) {
      queue.push(node)
    }
  }

  const sorted: T[] = []
  while (queue.length > 0) {
    const node = queue.shift()!
    sorted.push(node)

    // Reduce in-degree for all neighbors
    for (const neighbor of adjList.get(node)!) {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1)
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor)
      }
    }
  }

  // If we didn't process all nodes, there's a cycle
  if (sorted.length !== graph.nodes.length) {
    throw new Error("Cycle detected in graph")
  }

  return sorted
}
```

This implements Kahn's algorithm by tracking in-degrees, processing nodes with no dependencies first, and detecting cycles when the final sorted array doesn't include all nodes.

